@pytest.mark.parametrize("expected", ENUMS, ids=[item["enum"] for item in ENUMS])
def test_normative_enum_is_fixed_and_contains_only_declared_values(expected):
    registry = EnumRegistry.default()

    enum = registry.enum(expected["enum"])

    assert enum.name == expected["enum"]
    assert enum.fixed is True
    assert enum.values == expected["values"]
    assert enum.rejects_aliases is True


@pytest.mark.parametrize("expected", ENUM_CONTROLS, ids=[item["name"] for item in ENUM_CONTROLS])
def test_enum_value_is_enforced_across_schemas_actions_and_viewer(expected):
    registry = EnumRegistry.default()

    usage = registry.value_usage(expected["value"])

    assert usage.value == expected["value"]
    assert usage.accepted_by_schema_validation is True
    assert usage.accepted_by_action_validation is True
    assert usage.displayed_without_interface_aliases is True
